import{_ as a,c as t,a0 as i,o as r}from"./chunks/framework.BCLQlN4B.js";const u=JSON.parse('{"title":"IT邦 - 讓 TypeScript 成為你全端開發的 ACE !","description":"","frontmatter":{"title":"IT邦 - 讓 TypeScript 成為你全端開發的 ACE !"},"headers":[],"relativePath":"pages/docTypeScript/it/partI/typeScript-2.md","filePath":"pages/docTypeScript/it/partI/typeScript-2.md"}'),o={name:"pages/docTypeScript/it/partI/typeScript-2.md"};function c(l,e,p,d,n,s){return r(),t("div",null,e[0]||(e[0]=[i('<h1 id="_2-typescript-型別系統概論" tabindex="-1">2 TypeScript 型別系統概論 <a class="header-anchor" href="#_2-typescript-型別系統概論" aria-label="Permalink to &quot;2 TypeScript 型別系統概論&quot;">​</a></h1><h2 id="_2-1-型別系統的兩大基柱-型別的推論與註記" tabindex="-1">2.1 型別系統的兩大基柱 - 型別的推論與註記 <a class="header-anchor" href="#_2-1-型別系統的兩大基柱-型別的推論與註記" aria-label="Permalink to &quot;2.1 型別系統的兩大基柱 - 型別的推論與註記&quot;">​</a></h2><h3 id="_2-1-1-運用型別系統必備的核心觀念" tabindex="-1">2.1.1 運用型別系統必備的核心觀念 <a class="header-anchor" href="#_2-1-1-運用型別系統必備的核心觀念" aria-label="Permalink to &quot;2.1.1 運用型別系統必備的核心觀念&quot;">​</a></h3><ul><li>用 <code>文字</code> 標明該變數或函式的型別的方式稱為 <code>註記 (Annotation)</code>。</li><li>讓程式自己判斷某變數對應其值或運算過後的表達式之結果值的型別，則稱為 <code>推論(Inference)</code>。</li></ul><h3 id="_2-1-2-概觀型別推論與註記-各自的使用時機" tabindex="-1">2.1.2 概觀型別推論與註記 - 各自的使用時機 <a class="header-anchor" href="#_2-1-2-概觀型別推論與註記-各自的使用時機" aria-label="Permalink to &quot;2.1.2 概觀型別推論與註記 - 各自的使用時機&quot;">​</a></h3><ul><li><ol><li>核心守則 - <code>TypeScript</code> 的程式碼必須評估各種狀況選擇加上型別註記或者讓程式自行推論。</li></ol></li><li><ol start="2"><li>通常 <code>積極做註記是為了限縮型別的各種可能性</code>，使得程式碼可以減少要處理的例外狀況個數、增加模糊變數或方法使用上的 <code>可讀性</code> 以及讓 <code>TypeScript</code> 編譯器靜態偵測程式，<code>確保型別不會有衝突產生</code>。</li></ol></li><li><ol start="3"><li>如果某段或某行程式碼本身可讀性夠或者是從命名上直覺判斷出型別的機率夠高的話，通常 <code>TypeScript</code> 型別系統的推論機制就已足矣。</li></ol></li></ul><h2 id="_2-2-型別註記-『註記』與『斷言』的差異性" tabindex="-1">2.2 型別註記 - 『註記』與『斷言』的差異性 <a class="header-anchor" href="#_2-2-型別註記-『註記』與『斷言』的差異性" aria-label="Permalink to &quot;2.2 型別註記 - 『註記』與『斷言』的差異性&quot;">​</a></h2><h3 id="_2-2-1-型別註記語法" tabindex="-1">2.2.1 型別註記語法 <a class="header-anchor" href="#_2-2-1-型別註記語法" aria-label="Permalink to &quot;2.2.1 型別註記語法&quot;">​</a></h3><h2 id="_2-3-綜觀-typescript-型別種類" tabindex="-1">2.3 綜觀 TypeScript 型別種類 <a class="header-anchor" href="#_2-3-綜觀-typescript-型別種類" aria-label="Permalink to &quot;2.3 綜觀 TypeScript 型別種類&quot;">​</a></h2>',9)]))}const _=a(o,[["render",c]]);export{u as __pageData,_ as default};
